import numpy as np

class SparseDistributedMemory:
    def __init__(self, address_length, word_length, num_hard_locations, activation_radius, seed=42):
        self.address_length = address_length
        self.word_length = word_length
        self.activation_radius = activation_radius
        rng = np.random.RandomState(seed)
        self.hard_locations = rng.randint(0, 2, size=(num_hard_locations, address_length))
        self.counters = [[0] * word_length for _ in range(num_hard_locations)]

    def _hamming_distance(self, a, b):
        return sum(x != y for x, y in zip(a, b))

    def _activated_indices(self, address):
        return [
            i for i, loc in enumerate(self.hard_locations)
            if self._hamming_distance(address, loc) <= self.activation_radius
        ]

    def write(self, address, word):
        address = list(address)
        word = list(word)
        indices = self._activated_indices(address)
        for i in indices:
            for j, bit in enumerate(word):
                self.counters[i][j] += 1 if bit == 1 else -1
        return len(indices)

    def read(self, address):
        address = list(address)
        indices = self._activated_indices(address)
        if not indices:
            return [0] * self.word_length
        sums = [0] * self.word_length
        for i in indices:
            for j in range(self.word_length):
                sums[j] += self.counters[i][j]
        return [1 if s >= 0 else 0 for s in sums]
